appsmith.onReady(() => {
  const cookieData = appsmith.model.cookies || [];
  renderDashboard(cookieData);
  appsmith.onModelChange(newModel => {
    const updatedData = newModel.cookies || [];
    renderDashboard(updatedData);
  });
});
function renderDashboard(data) {
  const tbody = document.querySelector('#cookie-table tbody');
  const findingsList = document.getElementById('top-findings-list');
  if (!tbody) return;
  tbody.innerHTML = "";
  if (!data || !Array.isArray(data) || data.length === 0) {
    document.getElementById('leakage-count').textContent = "0";
    document.getElementById('js-risk-count').textContent = "0";
    document.getElementById('sovereignty-score').textContent = "0%";
    if (findingsList) findingsList.innerHTML = "<li>No baseline data loaded.</li>";
    return;
  }

  // 1. Calculations
  const thirdPartyCount = data.filter(c => c.thirdParty === true).length;
  const jsAccessibleCount = data.filter(c => c.httpOnly === false).length;
  const sovereigntyScore = Math.round((data.length - thirdPartyCount) / data.length * 100);

  // 2. Update UI Cards
  document.getElementById('leakage-count').textContent = thirdPartyCount;
  document.getElementById('js-risk-count').textContent = jsAccessibleCount;
  document.getElementById('sovereignty-score').textContent = `${sovereigntyScore}%`;

  // Update Disclosure Card
  const hasAnyPurpose = data.some(c => c.purpose && c.purpose !== "-");
  const disclosureEl = document.getElementById('disclosure-status');
  disclosureEl.textContent = hasAnyPurpose ? "Notice Present" : "Notice Missing";
  disclosureEl.style.color = hasAnyPurpose ? "#27ae60" : "#e74c3c";

  // 3. Build Top Findings
  if (findingsList) {
    findingsList.innerHTML = "";
    let findings = [];
    const criticalCookies = data.filter(c => c.thirdParty);
    if (criticalCookies.length > 0) {
      findings.push(`Observed ${criticalCookies.length} High Egress Signal(s) routing to External Entities (e.g., ${criticalCookies[0].domain || 'unknown domain'}).`);
    }
    const exposedJS = data.filter(c => !c.httpOnly);
    if (exposedJS.length > 0) {
      findings.push(`Detected ${exposedJS.length} instance(s) of JS Exposure Signals, lacking HTTPOnly protection.`);
    }
    const undisclosed = data.filter(c => !c.purpose || c.purpose === "-");
    if (undisclosed.length > 0) {
      findings.push(`Identified ${undisclosed.length} data point(s) missing explicit data usage purpose disclosures.`);
    }
    if (findings.length === 0) {
      findingsList.innerHTML = "<li>No critical exposure signals observed in the current baseline.</li>";
    } else {
      findings.slice(0, 3).forEach(f => {
        const li = document.createElement('li');
        li.textContent = f;
        li.style.marginBottom = "6px";
        findingsList.appendChild(li);
      });
    }
  }

  // 4. Build Table
  data.forEach(cookie => {
    const row = document.createElement('tr');

    // Risk Logic - Signal-based terminology
    let riskLabel = "Safe";
    let riskClass = "safe";
    if (cookie.thirdParty) {
      riskLabel = "High Egress Signal";
      riskClass = "critical";
    } else if (!cookie.httpOnly) {
      riskLabel = "JS Exposure Signal";
      riskClass = "warning";
    }
    const protection = cookie.httpOnly && cookie.secure ? "✅ Controls Active" : "⚠️ Exposure Signal";
    const isDisclosed = cookie.purpose && cookie.purpose !== "-" ? '<span class="badge badge-yes">YES</span>' : '<span class="badge badge-no">NO</span>';
    row.innerHTML = `
            <td><code>${cookie.name || 'unknown'}</code></td>
            <td>${cookie.domain || '-'}</td>
            <td>${cookie.thirdParty ? 'External Entity' : 'Internal Only'}</td>
            <td><span class="badge badge-${riskClass}">${riskLabel}</span></td>
            <td>${protection}</td>
            <td>${isDisclosed}</td>
        `;
    tbody.appendChild(row);
  });
}

